// ============================================
// CONFIGURATION v3.0 — ADR-030 Context-Aware Prompts
// n8n เรียกแค่ DMS Backend API เท่านั้น — ห้ามเรียก AI runtime โดยตรง (ADR-023A)
// v3 เพิ่ม: PROJECT_PUBLIC_ID + CONTRACT_PUBLIC_ID สำหรับ Master Data Context filter
// ============================================
const formData = $('Form Trigger').first()?.json || {};
const batchSizeInput = parseInt(String(formData['Batch Size'] || '0'));
const excelFileInput = String(formData['Excel File Path'] || '').trim();
const jwtTokenInput = String(formData['Migration Token'] || '').trim();
const resolvedExcelFile = excelFileInput || '/home/node/.n8n-files/staging_ai/C22024.xlsx';

// v3: อ่าน Project/Contract public UUID สำหรับ context filter (ADR-030 + ADR-019)
const projectPublicIdInput = String(formData['Project Public ID (UUID)'] || '').trim();
const contractPublicIdInput = String(formData['Contract Public ID (UUID)'] || '').trim();

// Validate Excel file path to prevent path traversal
if (resolvedExcelFile.includes('..') || resolvedExcelFile.includes('~')) {
  throw new Error('Invalid Excel file path: path traversal detected');
}

if (!jwtTokenInput || !jwtTokenInput.startsWith('Bearer ')) {
  throw new Error('JWT Token is required and must start with "Bearer "');
}

const BATCH_ID = (() => {
  // ใช้ Excel filename เป็น BATCH_ID เพื่อให้ checkpoint ทำงานถูกต้อง
  // เปลี่ยน Excel file = BATCH_ID ใหม่ = เริ่มใหม่ (ปลอดภัย)
  // ใช้ Excel file เดิม = BATCH_ID เดิม = resume ได้
  const filename = resolvedExcelFile.split('/').pop().split('\\').pop();
  const baseName = filename.replace(/\.xlsx?$/i, '');
  return baseName + '-MIGRATION';
})();

const CONFIG = {
  // Backend Settings
  BACKEND_URL: 'http://backend:3000',
  MIGRATION_TOKEN: jwtTokenInput,

  // Batch Settings
  BATCH_SIZE: batchSizeInput > 0 ? batchSizeInput : 10,
  BATCH_ID: BATCH_ID,
  DELAY_MS: 60000,

  // AI Job Settings (ADR-023A)
  AI_JOB_POLL_INTERVAL_MS: 5000,
  AI_JOB_TIMEOUT_MS: 120000,

  // File Settings
  EXCEL_FILE: resolvedExcelFile,
  SOURCE_PDF_DIR: '/home/node/.n8n-files/staging_ai/pdfs',
  LOG_PATH: '/home/node/.n8n-files/staging_ai/logs',

  // v3: Context Filter สำหรับ Master Data (ADR-030)
  // ใช้ public UUID เท่านั้นตาม ADR-019 — backend resolve เป็น internal id ภายใน service
  PROJECT_PUBLIC_ID: projectPublicIdInput || null,
  CONTRACT_PUBLIC_ID: contractPublicIdInput || null,
};

return [{ json: { config: CONFIG } }];

const fs = require('fs');
const config = $('Set Configuration').first().json.config;

try {
  if (!fs.existsSync(config.EXCEL_FILE)) {
    throw new Error(`Excel file not found at: ${config.EXCEL_FILE}`);
  }
  if (!fs.existsSync(config.SOURCE_PDF_DIR)) {
    throw new Error(`PDF Source directory not found at: ${config.SOURCE_PDF_DIR}`);
  }

  const files = fs.readdirSync(config.SOURCE_PDF_DIR);

  // Check write permission to log path
  fs.writeFileSync(`${config.LOG_PATH}/.preflight_ok`, new Date().toISOString());

  // Grab categories
  let categories = ['Correspondence','RFA','Drawing','Transmittal','Report','Other'];
  try {
    const upstreamData = $('Fetch Categories').first()?.json?.data;
    if (upstreamData && Array.isArray(upstreamData)) {
      categories = upstreamData.map(c => c.name || c.type || c);
    }
  } catch(e) {}

  // Grab existing tags
  let existingTags = [];
  try {
    const tagData = $('Fetch Tags').first()?.json?.data || [];
    existingTags = Array.isArray(tagData)
      ? tagData.map(t => ({ publicId: t.publicId, tagName: t.tag_name || t.name || '' })).filter(t => t.tagName && t.publicId)
      : [];
  } catch(e) {}

  return [{ json: { 
    preflight_ok: true, 
    pdf_count_in_source: files.length,
    excel_target: config.EXCEL_FILE,
    system_categories: categories,
    existing_tags: existingTags,
    timestamp: new Date().toISOString()
  }}];
} catch (err) {
  throw new Error(`Pre-flight check failed: ${err.message}`);
}

const cpJson = $input.first()?.json || {};
const startIndex = cpJson.data?.lastProcessedIndex ?? cpJson.lastProcessedIndex ?? cpJson.data?.last_processed_index ?? cpJson.last_processed_index ?? 0;
const config = $('Set Configuration').first().json.config;

const allItems = $('Read Excel').all().map(i => i.json);
const remaining = allItems.slice(startIndex);
const currentBatch = remaining.slice(0, config.BATCH_SIZE);

// Exit condition: ไม่มี records เหลือ
if (currentBatch.length === 0) {
  return [{ json: { batch_complete: true, total_processed: startIndex } }];
}

const normalize = (str) => {
  if (!str) return '';
  return String(str).normalize('NFC').trim();
};

return currentBatch.map((item, i) => {
  const getVal = (possibleKeys) => {
    const exactMatch = possibleKeys.find(k => item[k] !== undefined);
    if (exactMatch) return item[exactMatch];
    const lowerTrimmedKeys = Object.keys(item).map(k => ({ original: k, parsed: k.toLowerCase().trim() }));
    for (const pk of possibleKeys) {
      const found = lowerTrimmedKeys.find(k => k.parsed === pk.toLowerCase().trim());
      if (found) return item[found.original];
    }
    return '';
  };

  const docNum = getVal(['document_number', 'correspondence_number', 'Document Number', 'Corr. No.']);
  const excelFileName = getVal(['File name', 'file_name', 'File Name', 'filename']);

  if (!excelFileName) {
    throw new Error(`Missing 'File name' column for row ${i + startIndex + 1}, document: ${docNum}`);
  }

  return {
    json: {
      batch_complete: false,
      document_number: normalize(docNum),
      title: normalize(getVal(['title', 'Title', 'Subject', 'subject'])),
      legacy_number: normalize(getVal(['legacy_number', 'Legacy Number', 'Response Doc.'])),
      excel_revision: getVal(['revision', 'Revision', 'rev']) || 1,
      original_index: startIndex + i,
      batch_id: config.BATCH_ID,
      file_name: normalize(excelFileName),
    }
  };
});

const fs = require('fs');
const path = require('path');
const config = $('Set Configuration').first().json.config;

const items = $input.all();
if (!items || items.length === 0) return [];

// ตรวจสอบ exit condition
if (items[0]?.json?.batch_complete === true) {
  return items;
}

const validated = [];
const errors = [];

for (const item of items) {
  const fileName = item.json?.file_name;
  if (!fileName) {
    errors.push({ ...item, json: { ...item.json, file_valid: false, error: 'file_name is missing', error_type: 'MISSING_FILENAME' } });
    continue;
  }

  let safeName = path.basename(String(fileName)).normalize('NFC');
  if (!safeName.toLowerCase().endsWith('.pdf')) safeName += '.pdf';
  const filePath = path.resolve(config.SOURCE_PDF_DIR, safeName);

  if (!filePath.startsWith(path.resolve(config.SOURCE_PDF_DIR))) {
    errors.push({ ...item, json: { ...item.json, file_valid: false, error: 'Path traversal detected', error_type: 'SECURITY' } });
    continue;
  }

  try {
    if (fs.existsSync(filePath)) {
      const stats = fs.statSync(filePath);
      validated.push({ ...item, json: { ...item.json, file_valid: true, file_path: filePath, file_size: stats.size } });
    } else {
      errors.push({ ...item, json: { ...item.json, file_valid: false, error: `File not found: ${safeName}`, error_type: 'FILE_NOT_FOUND' } });
    }
  } catch (err) {
    errors.push({ ...item, json: { ...item.json, file_valid: false, error: err.message, error_type: 'FILE_ERROR' } });
  }
}

return [...validated, ...errors];

// v3: Build AI Job Payload พร้อม contextOverride สำหรับ Master Data filter (ADR-030)
const config = $('Set Configuration').first().json.config;
const uploadResponse = $input.first()?.json || {};
const metaItem = $('File Validator').all()[$input.context?.itemIndex ?? 0]?.json || {};
const mountCheckData = $('File Mount Check').first()?.json || {};

// Backend returns { data: { publicId, tempId, ... } } per ADR-019 (id is @Exclude'd)
const tempAttachmentPublicId = uploadResponse?.data?.publicId || uploadResponse?.publicId;
if (!tempAttachmentPublicId) {
  throw new Error(`Upload failed — no temp_attachment_public_id returned. Upload response: ${JSON.stringify(uploadResponse)}`);
}

// Validate required fields per DTO
const docNumber = String(metaItem.document_number || '').trim();
const docTitle = String(metaItem.title || '').trim();
if (!docNumber) {
  throw new Error(`document_number is empty for item: ${JSON.stringify(metaItem)}`);
}
if (!docTitle) {
  throw new Error(`title is empty for document: ${docNumber}`);
}

// Normalize existingTags to match TagOptionDto (tagName is required)
const existingTags = (mountCheckData.existing_tags || [])
  .filter(t => t.tagName && t.tagName.trim())
  .map(t => ({
    publicId: t.publicId || undefined,
    tagName: String(t.tagName).trim(),
    colorCode: t.colorCode || undefined,
  }));

// v3: contextOverride — ส่ง public UUID ให้ backend resolve master data context
// ตาม ADR-030: filter master data ตาม project/contract scope เพื่อลด context size
// null = ไม่ filter (ใช้ค่าจาก context_config ของ active prompt template)
const contextOverride = {
  projectPublicId: config.PROJECT_PUBLIC_ID || null,
  contractPublicId: config.CONTRACT_PUBLIC_ID || null,
};

// สร้าง SubmitAiJobDto ตาม Backend DTO (v3)
const submitPayload = {
  type: 'migrate-document',
  payload: {
    tempAttachmentId: String(tempAttachmentPublicId),
    documentNumber: docNumber,
    title: docTitle,
    batchId: String(config.BATCH_ID),
    existingTags: existingTags,
    systemCategories: mountCheckData.system_categories || [],
    // v3 NEW: contextOverride สำหรับ ADR-030 Master Data Context Filter
    contextOverride: contextOverride,
  }
};

// Idempotency-Key: deterministic format ตาม FR-001a
const idempotencyKey = `${config.BATCH_ID}:${docNumber}`;

return [{
  json: {
    ...metaItem,
    temp_attachment_public_id: tempAttachmentPublicId,
    submit_payload: submitPayload,
    idempotency_key: idempotencyKey,
  }
}];

// Poll GET /api/ai/jobs/{jobId} ทุก 5 วินาที จน status = completed หรือ timeout 120 วินาที
const config = $('Set Configuration').first().json.config;
const submitResponse = $input.first()?.json || {};
const originalMeta = $('Build AI Job Payload').all()[$input.context?.itemIndex ?? 0]?.json || {};

const jobId = submitResponse?.jobId || submitResponse?.data?.jobId;
if (!jobId) {
  // FR-010b: ถ้า 401 → mark TOKEN_EXPIRED
  if (submitResponse?.statusCode === 401 || submitResponse?.error?.status === 401) {
    throw new Error('TOKEN_EXPIRED: 401 Unauthorized — กรุณา renew MIGRATION_TOKEN แล้ว resume');
  }
  throw new Error(`Submit AI Job failed — no jobId returned for: ${originalMeta.document_number}`);
}

const pollIntervalMs = config.AI_JOB_POLL_INTERVAL_MS || 5000;
const timeoutMs = config.AI_JOB_TIMEOUT_MS || 120000;
const startTime = Date.now();

while (true) {
  if (Date.now() - startTime > timeoutMs) {
    throw new Error(`AI Job timeout after ${timeoutMs}ms for jobId: ${jobId}, document: ${originalMeta.document_number}`);
  }

  const statusResponse = await $helpers.httpRequest({
    method: 'GET',
    url: `${config.BACKEND_URL}/api/ai/jobs/${jobId}`,
    headers: { 'Authorization': config.MIGRATION_TOKEN },
    json: true
  });

  const status = statusResponse?.status || statusResponse?.data?.status;

  if (status === 'completed') {
    return [{
      json: {
        ...originalMeta,
        job_id: jobId,
        ai_result: statusResponse?.result || statusResponse?.data?.result || {},
        ai_status: 'completed',
      }
    }];
  }

  if (status === 'failed') {
    return [{
      json: {
        ...originalMeta,
        job_id: jobId,
        ai_status: 'failed',
        parse_error: `AI Job failed: ${JSON.stringify(statusResponse?.error || statusResponse?.data?.error || 'unknown')}`,
        error_type: 'AI_JOB_FAILED',
        route_index: 3,
      }
    }];
  }

  // ยังไม่เสร็จ → รอแล้ว poll ใหม่
  await new Promise(resolve => setTimeout(resolve, pollIntervalMs));
}

// v3: Parse & Validate AI Response — รองรับ 11-field schema (ADR-030)
// recipients เป็น Array<{ organizationPublicId, recipientType }> แทน parallel arrays
const config = $('Set Configuration').first().json.config;
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // ถ้า poll ส่ง error กลับมาโดยตรง (route_index = 3)
  if (data.route_index === 3 || data.ai_status === 'failed') {
    results.push({ json: { ...data, route_index: 3 } });
    continue;
  }

  const ai = data.ai_result || {};

  if (!ai || typeof ai !== 'object') {
    results.push({ json: { ...data, parse_error: 'Empty or invalid ai_result', error_type: 'PARSE_ERROR', route_index: 3 } });
    continue;
  }

  // ================================================================
  // v3: 11-field schema validation (ADR-030)
  // ================================================================

  // 1. projectPublicId — UUID string หรือ null
  const projectPublicId = typeof ai.projectPublicId === 'string' && ai.projectPublicId.trim()
    ? ai.projectPublicId.trim()
    : null;

  // 2. correspondenceTypeCode — รหัสประเภท เช่น RFA, LETTER, TRANSMITTAL
  const correspondenceTypeCode = typeof ai.correspondenceTypeCode === 'string' && ai.correspondenceTypeCode.trim()
    ? ai.correspondenceTypeCode.trim().toUpperCase()
    : null;

  // 3. disciplineCode — รหัสสาขางาน เช่น GEN, STR
  const disciplineCode = typeof ai.disciplineCode === 'string' && ai.disciplineCode.trim()
    ? ai.disciplineCode.trim().toUpperCase()
    : null;

  // 4. originatorOrganizationPublicId — UUID string หรือ null
  const originatorOrganizationPublicId = typeof ai.originatorOrganizationPublicId === 'string' && ai.originatorOrganizationPublicId.trim()
    ? ai.originatorOrganizationPublicId.trim()
    : null;

  // 5. recipients — Object Array ตาม spec ADR-030
  // รูปแบบ: Array<{ organizationPublicId: string, recipientType: 'TO' | 'CC' }>
  // ห้ามใช้ parallel arrays (recipientOrganizationPublicIds + recipientTypes)
  let recipients = [];
  if (Array.isArray(ai.recipients)) {
    recipients = ai.recipients
      .filter(r => r && typeof r === 'object' && typeof r.organizationPublicId === 'string' && r.organizationPublicId.trim())
      .map(r => ({
        organizationPublicId: String(r.organizationPublicId).trim(),
        recipientType: ['TO', 'CC'].includes(String(r.recipientType || '').trim().toUpperCase())
          ? String(r.recipientType).trim().toUpperCase()
          : 'TO',
      }));
  }

  // 6. subject — หัวข้อเอกสาร
  const subject = typeof ai.subject === 'string' && ai.subject.trim()
    ? ai.subject.trim()
    : data.title || '';

  // 7. documentDate — YYYY-MM-DD
  const documentDate = typeof ai.documentDate === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(ai.documentDate.trim())
    ? ai.documentDate.trim()
    : null;

  // 8. tags — string[]
  const suggestedTags = Array.isArray(ai.tags)
    ? ai.tags.map(t => {
        if (typeof t === 'string') return { tagName: t.trim(), isNew: true, colorCode: 'default' };
        if (typeof t === 'object' && t.tagName) return {
          tagName: String(t.tagName || t.tag_name || '').trim(),
          publicId: t.publicId || t.public_id || undefined,
          isNew: Boolean(t.isNew ?? t.is_new ?? !t.publicId),
          colorCode: t.colorCode || t.color_code || 'default',
        };
        return null;
      }).filter(t => t && t.tagName)
    : [];

  // 9. summary — ภาษาไทย 4-5 ประโยค
  const summary = typeof ai.summary === 'string' && ai.summary.trim() ? ai.summary.trim() : null;

  // 10. confidence — float 0-1
  const confidence = typeof ai.confidence === 'number' ? Math.max(0, Math.min(1, ai.confidence)) : 0;

  // ================================================================
  // Confidence-based routing (เหมือน v2)
  // route_index: 0=Auto Ready, 1=Review Flagged, 2=Rejected, 3=Error Log
  // ================================================================
  let route_index;
  let review_reason = '';
  let reject_reason = '';

  // ตรวจสอบ UUID fields ที่จำเป็น — ถ้าไม่มี → Flagged เพื่อ human validation
  const missingUuids = [];
  if (!projectPublicId) missingUuids.push('projectPublicId');
  if (!originatorOrganizationPublicId) missingUuids.push('originatorOrganizationPublicId');
  if (recipients.length === 0) missingUuids.push('recipients');

  if (missingUuids.length > 0) {
    route_index = 1;
    review_reason = `UUID fields ไม่ครบ: ${missingUuids.join(', ')} — ต้องการ human validation (ADR-030)`;
  } else if (confidence >= 0.85) {
    route_index = 0; // Auto Ready
  } else if (confidence >= 0.50) {
    route_index = 1; // Review Flagged
    review_reason = `confidence ต่ำ (${confidence.toFixed(2)}) — ต้องการ human review`;
  } else if (confidence > 0) {
    route_index = 2; // Rejected
    reject_reason = `confidence ต่ำเกิน (${confidence.toFixed(2)}) — ต่ำกว่า threshold 0.50`;
  } else {
    route_index = 3; // Error
  }

  const normalizedAi = {
    // v3: 11-field schema (ADR-030)
    projectPublicId,
    correspondenceTypeCode,
    disciplineCode,
    originatorOrganizationPublicId,
    recipients,
    subject,
    documentDate,
    tags: suggestedTags,
    summary,
    confidence,
  };

  results.push({
    json: {
      ...data,
      ai_result: normalizedAi,
      review_reason,
      reject_reason,
      route_index,
    }
  });
}

return results;

const fs = require('fs');
const item = $input.first();
const config = $('Set Configuration').first().json.config;

const csvPath = `${config.LOG_PATH}/reject_log_${config.BATCH_ID}.csv`;
const header = 'timestamp,document_number,title,reject_reason,ai_confidence,job_id\n';
const esc = (s) => `"${String(s || '').replace(/"/g, '""')}"`;

if (!fs.existsSync(csvPath)) {
  fs.writeFileSync(csvPath, header, 'utf8');
}

const line = [
  new Date().toISOString(),
  esc(item.json.document_number),
  esc(item.json.title),
  esc(item.json.reject_reason),
  item.json.ai_result?.confidence ?? 'N/A',
  esc(item.json.job_id || '')
].join(',') + '\n';

fs.appendFileSync(csvPath, line, 'utf8');

return [$input.first()];

const fs = require('fs');
const items = $input.all();
const config = $('Set Configuration').first().json.config;

const ERROR_TYPE_MAP = {
  AI_JOB_FAILED: 'API_ERROR',
  PARSE_ERROR: 'AI_PARSE_ERROR',
  TOKEN_EXPIRED: 'API_ERROR',
};
const ALLOWED_ERROR_TYPES = new Set([
  'FILE_NOT_FOUND',
  'MISSING_FILENAME',
  'FILE_ERROR',
  'AI_PARSE_ERROR',
  'API_ERROR',
  'DB_ERROR',
  'SECURITY',
  'UNKNOWN',
]);
const normalizeErrorType = (type) => {
  const mappedType = ERROR_TYPE_MAP[type] || type || 'UNKNOWN';
  return ALLOWED_ERROR_TYPES.has(mappedType) ? mappedType : 'UNKNOWN';
};

const csvPath = `${config.LOG_PATH}/error_log_${config.BATCH_ID}.csv`;
const header = 'timestamp,document_number,error_type,error_message,job_id\n';
const esc = (s) => `"${String(s || '').replace(/"/g, '""')}"`;

if (!fs.existsSync(csvPath)) {
  fs.writeFileSync(csvPath, header, 'utf8');
}

for (const item of items) {
  item.json.document_number = item.json.document_number || 'WORKFLOW';
  item.json.error_type = normalizeErrorType(item.json.error_type);
  item.json.error = item.json.error || item.json.parse_error || item.json.message || '';
  item.json.job_id = item.json.job_id || '';

  const line = [
    new Date().toISOString(),
    esc(item.json.document_number),
    esc(item.json.error_type),
    esc(item.json.error),
    esc(item.json.job_id)
  ].join(',') + '\n';
  fs.appendFileSync(csvPath, line, 'utf8');
}

return items;
